mapper.select:
SELECT a.ACTIVITY_ID , a.GURU_CD , g.INVESTOR_NM , g.INVESTOR_KO_NM , g.INVESTOR_NICKNAME , a.ACTIVITY_TYPE , a.ISSUER_NM , a.TICKER , a.ACTIVITY_DATE , a.ACTIVITY_YEAR , a.ACTIVITY_QTR , a.CHANGE_PCT , a.NOTES , a.REG_DT FROM tbl_guru_recent_activity a JOIN tbl_guru g ON g.GURU_CD = a.GURU_CD WHERE 1=1
AND a.GURU_CD = #{searchRequest.guruCd}
AND a.ACTIVITY_TYPE = #{searchRequest.activityType}
AND a.TICKER = #{searchRequest.ticker}
AND a.ACTIVITY_DATE = #{searchRequest.activityDate}
ORDER BY a.ACTIVITY_ID DESC

SELECT t.ACTIVITY_ID , t.GURU_CD , g.INVESTOR_NM , g.INVESTOR_KO_NM , g.INVESTOR_NICKNAME , t.ACTIVITY_TYPE , t.ISSUER_NM , t.TICKER , t.ACTIVITY_DATE , t.ACTIVITY_YEAR , t.ACTIVITY_QTR , t.CHANGE_PCT , t.NOTES , t.REG_DT FROM ( SELECT a.* , ROW_NUMBER() OVER (PARTITION BY a.TICKER ORDER BY a.ACTIVITY_YEAR DESC, a.ACTIVITY_QTR DESC, a.ACTIVITY_ID DESC) AS rn FROM tbl_guru_recent_activity a WHERE 1=1
AND a.GURU_CD = #{guruCd}
) t JOIN tbl_guru g ON g.GURU_CD = t.GURU_CD WHERE t.rn = 1 ORDER BY t.TICKER ASC
